123	  } else {
124	    log('已登录状态');
125	  }
126	
127	  // ---- Step 3: 导航到 TM 消息页面 ----
128	  log('导航到 TM 消息页...');
129	  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
130	  await sleep(3000);
131	
132	  // 可能需要点击侧边栏进入 TM（OKKI 的 /im/ 可能只显示外壳，onetalk 在 iframe 里）
133	  log(`当前 URL: ${page.url()}`);
134	
135	  // ---- Step 4: 等待 onetalk iframe + 数据就绪 ----
136	  log('等待 onetalk iframe 加载...');
137	
138	  // 递归查找 onetalk 页面（可能在嵌套 iframe 中）
139	  function findOnetalkFrame(pageOrFrame) {
140	    const frames = pageOrFrame.frames ? pageOrFrame.frames() : (pageOrFrame.childFrames ? pageOrFrame.childFrames() : []);
141	    for (const f of frames) {
142	      const url = f.url();
143	      // 真正的 onetalk PWA 页面，不是 OKKI 外壳
144	      if (url.startsWith('https://onetalk.alibaba.com/')) return f;
145	      // 递归查找
146	      const found = findOnetalkFrame(f);
147	      if (found) return found;
148	    }
149	    return null;
150	  }
151	
152	  let iframePage = null;
153	  for (let attempt = 0; attempt < 30; attempt++) {
154	    iframePage = findOnetalkFrame(page);
155	    if (iframePage) {
156	      log(`onetalk iframe 已找到 (尝试 ${attempt + 1}): ${iframePage.url().slice(0, 100)}`);
