225	    if (attempt === 0) {
226	      log(`  等待 TM 数据加载 (${convData.error || '空数据'})...`);
227	    }
228	    await sleep(2000);
229	  }
230	
231	  if (!convData || convData.error || convData.count === 0) {
232	    log(`提取失败: ${convData?.error || '无数据'}`);
233	    log('TM 面板可能未正常加载。请确认能看到会话列表后重新运行脚本。');
234	    await browser.close();
235	    process.exit(1);
