269	
270	  for (const c of convList) {
271	    const old = oldMap.get(c.cid);
272	    if (!old) {
273	      // 新会话
274	      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
