350	    // 确认 WS 已捕获
351	    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
352	      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
353	    );
354	    log(`WS 状态: ${JSON.stringify(wsState)}`);
355	
356	    if (!wsState?.ws) {
357	      log('等待 WebSocket 连接...');
358	      await sleep(15000);
359	      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
360	        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
361	      );
362	      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
363	    }
364	
365	    // 拉取消息
366	    let pulled = 0;
367	    let errors = 0;
368	    let totalNewMsgs = 0;
369	    let msgIdCounter = 100;
370	
371	    for (let i = 0; i < changed.length; i++) {
372	      const conv = changed[i];
373	      try {
374	        const allMessages = [];
375	        let cursor = 9007199254740991;
376	        let pageNum = 0;
377	
378	        while (pageNum < MAX_PAGES) {
379	          const msgId = msgIdCounter++;
380	          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
381	            `(async function() {
382	              try {
383	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
384	                return JSON.stringify(result);
385	              } catch(e) {
386	                return JSON.stringify({ __error: e.message });
387	              }
388	            })()`,
389	            true
390	          );
391	
392	          await sleep(1500);
393	
394	          if (!raw || raw.__error) {
395	            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
396	            break;
397	          }
398	
399	          let response;
400	          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
401	          if (response.code !== 200) break;
402	
403	          const body = response.body;
404	          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;
405	
406	          allMessages.push(...body.userMessageModels);
407	
408	          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
409	          cursor = body.nextCursor;
410	          pageNum++;
411	        }
412	
413	        // 保存
414	        const safeName = sanitizeFilename(conv.cid);
415	        const output = {
416	          cid: conv.cid,
417	          name: conv.name,
418	          fetchedAt: new Date().toISOString(),
419	          totalMessages: allMessages.length,
420	          messages: allMessages,
421	        };
422	        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
423	        pulled++;
