425	        if (allMessages.length > 0) {
426	          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
427	        }
428	      } catch (e) {
429	        errors++;
430	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
431	      }
432	    }
433	
434	    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
435	  } else {
436	    log('跳过 LWP 拉取（无 CDP/iframe 访问）');
437	    log('已保存元数据差异。在新对话中可通过 STATE.md 了解哪些客户需要深抓。');
438	  }
